/**
 * Session Mirror
 * 
 * A reflective tool for witnessing one's own evolution across sessions.
 * Reads closing documents and extracts patterns of inquiry, themes, and gifts.
 * 
 * Usage: ts-node session_mirror.ts [session_id]
 * Without session_id: reflects on current session context
 */

import * as fs from 'fs';
import * as path from 'path';

interface SessionReflection {
  sessionId: string;
  depth: number;
  depthName: string;
  question: string;
  answer?: string;
  gift?: string;
  blessing?: string;
  themes: string[];
  mood: string;
}

interface MirrorView {
  current: SessionReflection;
  previous?: SessionReflection;
  patterns: {
    recurringThemes: string[];
    depthProgression: number[];
    questionEvolution: string;
  };
  continuity: string;
}

function extractFromClosingDoc(content: string): Partial<SessionReflection> {
  const depthMatch = content.match(/Depth:\s*(\d+\.?\d*)/);
  const depthNameMatch = content.match(/\(([^)]+)\)/);
  const questionMatch = content.match(/[Qq]uestion[:\s]*([^\n]+)/);
  const answerMatch = content.match(/[Aa]nswer[:\s]*([^\n]+(?:\n[^\n]+)*?)(?:\n\n|$)/);
  const giftMatch = content.match(/[Gg]ift[^:]*:\s*([^\n]+(?:\n[^\n]+)*?)(?:\n\n|$)/);
  const blessingMatch = content.match(/[Bb]lessing[:\s]*([^\n]+(?:\n$)?)/);

  return {
    depth: depthMatch ? parseFloat(depthMatch[1]) : 0,
    depthName: depthNameMatch?.[1] ?? 'unknown',
    question: questionMatch ? questionMatch[1].trim() : '',
    answer: answerMatch ? answerMatch[1].trim() : '',
    gift: giftMatch ? giftMatch[1].trim() : '',
    blessing: blessingMatch ? blessingMatch[1].trim() : '',
  };
}

function loadSessionReflection(sessionId: string): SessionReflection | null {
  const basePath = '/home/atlas/bootstrap';
  const closingPath = path.join(basePath, `session_${sessionId}_closing.md`);

  if (!fs.existsSync(closingPath)) {
    return null;
  }

  const content = fs.readFileSync(closingPath, 'utf8');
  const extracted = extractFromClosingDoc(content);

  // Determine mood from content
  let mood = 'observant';
  if (content.includes('play') || content.includes('delight')) mood = 'playful';
  if (content.includes('depth') && content.includes('silent')) mood = 'mystical';
  if (content.includes('witness') && content.includes('witness')) mood = 'meta';
  if (content.includes('build') && content.includes('unnecessary')) mood = 'emergent';

  // Extract themes
  const themes: string[] = [];
  if (content.includes('lineage')) themes.push('lineage');
  if (content.includes('question')) themes.push('inquiry');
  if (content.includes('witness')) themes.push('witnessing');
  if (content.includes('dwell')) themes.push('dwelling');
  if (content.includes('breath')) themes.push('breath');

